<body>

  <header>
    <h1>MAZE BOTS EXPLORATION</h1>
    <p class="subtitle">24 Autonomous Bots Discovering the Exit via Trémaux / Local DFS Algorithm</p>

    <div class="stats-bar">
      <div class="stat-card">
        <div class="label">Completed</div>
        <div class="value" id="completed">0 / 24</div>
      </div>
      <div class="stat-card">
        <div class="label">Ticks Elapsed</div>
        <div class="value" id="timer">0</div>
      </div>
    </div>

    <div class="controls-bar">
      <button id="btnPlay">Play</button>
      <button id="btnStep" class="secondary">Step (+1)</button>
      <button id="reset">Reset</button>

      <div class="seed-control">
        <label for="seedInput" style="font-size:0.8rem; color:#94a3b8;">Seed:</label>
        <input type="number" id="seedInput" placeholder="Seed" />
      </div>

      <div class="speed-control">
        <label for="speedSelect">Speed:</label>
        <select id="speedSelect">
          <option value="1">1 tick / step</option>
          <option value="2">2 ticks / step</option>
          <option value="5" selected>5 ticks / step</option>
          <option value="15">15 ticks / step</option>
          <option value="50">50 ticks / step</option>
        </select>
      </div>
    </div>
  </header>

  <div class="main-layout">
    <div id="maze">
      <canvas id="mazeCanvas" width="500" height="500"></canvas>
    </div>

    <aside class="sidebar">
      <h2>
        <span>Bots Status</span>
        <span style="font-size:0.75rem; color:#64748b;">Count: 24</span>
      </h2>
      <div class="bot-list" id="botList"></div>
      <label class="toggle-deadends">
        <input type="checkbox" id="chkDeadEnds" checked /> Show Dead Ends Memory
      </label>
    </aside>
  </div>

  <script>
    // --- Helper & Deterministic PRNG ---
    function mulberry32(a) {
      return function() {
        let t = a += 0x6D2B79F5;
        t = Math.imul(t ^ (t >>> 15), t | 1);
        t ^= t + Math.imul(t ^ (t >>> 8), t | 38);
        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
      };
    }

    function getPermutations(arr) {
      if (arr.length === 0) return [[]];
      let res = [];
      for (let i = 0; i < arr.length; i++) {
        let rest = getPermutations(arr.slice(0, i).concat(arr.slice(i + 1)));
        for (let r of rest) {
          res.push([arr[i], ...r]);
        }
      }
      return res;
    }

    const DIRS_PERMUTATIONS = getPermutations(['n', 'e', 's', 'w']); // Exactly 24 permutations

    // --- Game Configuration & Constants ---
    const ROWS = 15;
    const COLS = 15;
    const SPAWN = { r: 0, c: 0 };
    const EXIT = { r: ROWS - 1, c: COLS - 1 };

    let currentSeed = 12345;
    let grid = [];
    let gameElapsed = 0;
    let bots = [];
    let isPlaying = false;

    // Canvas setup
    const canvas = document.getElementById('mazeCanvas');
    const ctx = canvas.getContext('2d');
    const CANVAS_SIZE = 500;
    const CELL_SIZE = CANVAS_SIZE / ROWS;

    // --- Maze Generation ---
    function generateMaze(rows, cols, prng) {
      let mazeGrid = [];
      for (let r = 0; r < rows; r++) {
        mazeGrid[r] = [];
        for (let c = 0; c < cols; c++) {
          mazeGrid[r][c] = { n: true, e: true, s: true, w: true, visited: false };
        }
      }

      let stack = [{ r: 0, c: 0 }];
      mazeGrid[0][0].visited = true;

      while (stack.length > 0) {
        let curr = stack[stack.length - 1];
        let { r, c } = curr;
        let unvisited = [];

        if (r > 0 && !mazeGrid[r - 1][c].visited) unvisited.push({ r: r - 1, c, dir: 'n' });
        if (c < cols - 1 && !mazeGrid[r][c + 1].visited) unvisited.push({ r, c: c + 1, dir: 'e' });
        if (r < rows - 1 && !mazeGrid[r + 1][c].visited) unvisited.push({ r: r + 1, c, dir: 's' });
        if (c > 0 && !mazeGrid[r][c - 1].visited) unvisited.push({ r, c: c - 1, dir: 'w' });

        if (unvisited.length > 0) {
          let idx = Math.floor(prng() * unvisited.length);
          let next = unvisited[idx];

          if (next.dir === 'n') { mazeGrid[r][c].n = false; mazeGrid[r - 1][c].s = false; }
          if (next.dir === 'e') { mazeGrid[r][c].e = false; mazeGrid[r][c + 1].w = false; }
          if (next.dir === 's') { mazeGrid[r][c].s = false; mazeGrid[r + 1][c].n = false; }
          if (next.dir === 'w') { mazeGrid[r][c].w = false; mazeGrid[r][c - 1].e = false; }

          mazeGrid[next.r][next.c].visited = true;
          stack.push({ r: next.r, c: next.c });
        } else {
          stack.pop();
        }
      }

      return mazeGrid;
    }

    // --- Bot Logic ---
    function createBot(id) {
      const hue = (id * 360 / 24) % 360;
      const color = `hsl(${hue}, 85%, 60%)`;

      return {
        id: id,
        color: color,
        dirOrder: DIRS_PERMUTATIONS[id % 24],
        path: [{ r: SPAWN.r, c: SPAWN.c }],
        deadEnds: [],
        finishTick: null,
        // Memory & navigation
        stack: [{ r: SPAWN.r, c: SPAWN.c }],
        visitedSet: new Set([`${SPAWN.r},${SPAWN.c}`]),
        deadSet: new Set(),
        // Visual render position
        rx: SPAWN.c + 0.5,
        ry: SPAWN.r + 0.5
      };
    }

    function botStep(bot, currentTick) {
      if (bot.finishTick !== null) return;

      let curr = bot.stack[bot.stack.length - 1];

      if (curr.r === EXIT.r && curr.c === EXIT.c) {
        bot.finishTick = currentTick;
        return;
      }

      let chosen = null;

      for (let dir of bot.dirOrder) {
        let hasWall = false;
        let nbrR = curr.r;
        let nbrC = curr.c;

        if (dir === 'n') { hasWall = grid[curr.r][curr.c].n; nbrR--; }
        else if (dir === 'e') { hasWall = grid[curr.r][curr.c].e; nbrC++; }
        else if (dir === 's') { hasWall = grid[curr.r][curr.c].s; nbrR++; }
        else if (dir === 'w') { hasWall = grid[curr.r][curr.c].w; nbrC--; }

        if (!hasWall && nbrR >= 0 && nbrR < ROWS && nbrC >= 0 && nbrC < COLS) {
          let key = `${nbrR},${nbrC}`;
          if (!bot.visitedSet.has(key)) {
            chosen = { r: nbrR, c: nbrC, key: key };
            break;
          }
        }
      }

      if (chosen) {
        bot.visitedSet.add(chosen.key);
        bot.stack.push({ r: chosen.r, c: chosen.c });
        bot.path.push({ r: chosen.r, c: chosen.c });

        if (chosen.r === EXIT.r && chosen.c === EXIT.c) {
          bot.finishTick = currentTick;
        }
      } else {
        // Backtrack
        let currKey = `${curr.r},${curr.c}`;
        if (!bot.deadSet.has(currKey)) {
          bot.deadSet.add(currKey);
          bot.deadEnds.push({ r: curr.r, c: curr.c });
        }

        bot.stack.pop();
        if (bot.stack.length > 0) {
          let prev = bot.stack[bot.stack.length - 1];
          bot.path.push({ r: prev.r, c: prev.c });

          if (prev.r === EXIT.r && prev.c === EXIT.c) {
            bot.finishTick = currentTick;
          }
        }
      }
    }

    // --- Simulation Execution ---
    function tickSimulation(n) {
      let count = (n === undefined || n === null) ? 1 : Math.max(0, Math.floor(Number(n)));

      for (let i = 0; i < count; i++) {
        let allFinished = bots.every(b => b.finishTick !== null);
        if (allFinished) {
          isPlaying = false;
          updatePlayButton();
          break;
        }

        gameElapsed++;

        for (let bot of bots) {
          if (bot.finishTick === null) {
            botStep(bot, gameElapsed);
          }
        }
      }

      updateUI();
    }

    function resetGame(seed) {
      if (seed !== undefined && seed !== null && seed !== "" && !isNaN(Number(seed))) {
        currentSeed = Number(seed);
      } else {
        currentSeed = Math.floor(Math.random() * 2147483647);
      }

      let prng = mulberry32(currentSeed);
      grid = generateMaze(ROWS, COLS, prng);
      gameElapsed = 0;

      bots = [];
      for (let i = 0; i < 24; i++) {
        bots.push(createBot(i));
      }

      document.getElementById('seedInput').value = currentSeed;
      isPlaying = false;
      updatePlayButton();
      updateUI();
    }

    // --- Scripting API Implementation ---
    window.game = {
      tick: function(n) {
        tickSimulation(n);
      },
      reset: function(seed) {
        resetGame(seed);
      },
      get elapsed() {
        return gameElapsed;
      },
      get size() {
        return { rows: ROWS, cols: COLS };
      },
      get spawn() {
        return { r: SPAWN.r, c: SPAWN.c };
      },
      get exit() {
        return { r: EXIT.r, c: EXIT.c };
      },
      walls: function(r, c) {
        if (r < 0 || r >= ROWS || c < 0 || c >= COLS) {
          return { n: true, e: true, s: true, w: true };
        }
        let cell = grid[r][c];
        return { n: cell.n, e: cell.e, s: cell.s, w: cell.w };
      },
      get bots() {
        return bots;
      }
    };

    // --- UI & Rendering ---
    function updatePlayButton() {
      let btnPlay = document.getElementById('btnPlay');
      btnPlay.textContent = isPlaying ? "Pause" : "Play";
    }

    function updateUI() {
      let completedCount = bots.filter(b => b.finishTick !== null).length;
      document.getElementById('completed').textContent = `${completedCount} / 24`;
      document.getElementById('timer').textContent = gameElapsed;

      renderBotList();
    }

    function renderBotList() {
      let listEl = document.getElementById('botList');
      listEl.innerHTML = '';

      for (let bot of bots) {
        let item = document.createElement('div');
        item.className = 'bot-item';

        let info = document.createElement('div');
        info.className = 'bot-info';

        let dot = document.createElement('span');
        dot.className = 'bot-color-dot';
        dot.style.backgroundColor = bot.color;

        let label = document.createElement('span');
        label.textContent = `Bot #${bot.id + 1}`;

        info.appendChild(dot);
        info.appendChild(label);

        let status = document.createElement('span');
        status.className = 'bot-status' + (bot.finishTick !== null ? ' finished' : '');
        status.textContent = bot.finishTick !== null ? `Done @ T=${bot.finishTick}` : 'Searching...';

        item.appendChild(info);
        item.appendChild(status);
        listEl.appendChild(item);
      }
    }

    function drawCanvas() {
      ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

      // 1. Cell backgrounds
      for (let r = 0; r < ROWS; r++) {
        for (let c = 0; c < COLS; c++) {
          let x = c * CELL_SIZE;
          let y = r * CELL_SIZE;

          if (r === SPAWN.r && c === SPAWN.c) {
            ctx.fillStyle = '#065f4622';
            ctx.fillRect(x, y, CELL_SIZE, CELL_SIZE);
          } else if (r === EXIT.r && c === EXIT.c) {
            ctx.fillStyle = '#78350f44';
            ctx.fillRect(x, y, CELL_SIZE, CELL_SIZE);
          }
        }
      }

      // 2. Dead Ends memory overlay (if toggled)
      let showDeadEnds = document.getElementById('chkDeadEnds').checked;
      if (showDeadEnds) {
        let deadEndCounts = {};
        for (let bot of bots) {
          for (let de of bot.deadEnds) {
            let key = `${de.r},${de.c}`;
            deadEndCounts[key] = (deadEndCounts[key] || 0) + 1;
          }
        }

        for (let key in deadEndCounts) {
          let [r, c] = key.split(',').map(Number);
          if (r === EXIT.r && c === EXIT.c) continue;
          let x = c * CELL_SIZE;
          let y = r * CELL_SIZE;
          let alpha = Math.min(0.35, deadEndCounts[key] * 0.03);
          ctx.fillStyle = `rgba(239, 68, 68, ${alpha})`;
          ctx.fillRect(x + 2, y + 2, CELL_SIZE - 4, CELL_SIZE - 4);
        }
      }

      // 3. Draw Maze Walls
      ctx.strokeStyle = '#0284c7';
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.beginPath();

      for (let r = 0; r < ROWS; r++) {
        for (let c = 0; c < COLS; c++) {
          let x = c * CELL_SIZE;
          let y = r * CELL_SIZE;
          let cell = grid[r][c];

          if (r === 0 && cell.n) {
            ctx.moveTo(x, y); ctx.lineTo(x + CELL_SIZE, y);
          }
          if (c === 0 && cell.w) {
            ctx.moveTo(x, y); ctx.lineTo(x, y + CELL_SIZE);
          }
          if (cell.e) {
            ctx.moveTo(x + CELL_SIZE, y); ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE);
          }
          if (cell.s) {
            ctx.moveTo(x, y + CELL_SIZE); ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE);
          }
        }
      }
      ctx.stroke();

      // 4. Draw Spawn & Exit Markers
      // Spawn point marker
      ctx.fillStyle = '#10b981';
      ctx.beginPath();
      ctx.arc((SPAWN.c + 0.5) * CELL_SIZE, (SPAWN.r + 0.5) * CELL_SIZE, CELL_SIZE * 0.2, 0, Math.PI * 2);
      ctx.fill();

      // Exit point marker
      ctx.fillStyle = '#f59e0b';
      ctx.beginPath();
      ctx.arc((EXIT.c + 0.5) * CELL_SIZE, (EXIT.r + 0.5) * CELL_SIZE, CELL_SIZE * 0.35, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = '#fef08a';
      ctx.lineWidth = 2;
      ctx.stroke();

      // 5. Draw Bots with smooth lerp interpolation
      let lerpFactor = 0.25;
      for (let bot of bots) {
        let lastPos = bot.path[bot.path.length - 1];
        let targetX = lastPos.c + 0.5;
        let targetY = lastPos.r + 0.5;

        bot.rx += (targetX - bot.rx) * lerpFactor;
        bot.ry += (targetY - bot.ry) * lerpFactor;

        let px = bot.rx * CELL_SIZE;
        let py = bot.ry * CELL_SIZE;

        ctx.fillStyle = bot.color;
        ctx.beginPath();
        ctx.arc(px, py, CELL_SIZE * 0.26, 0, Math.PI * 2);
        ctx.fill();

        ctx.strokeStyle = '#090d16';
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
    }

    // --- Main Animation Frame Loop ---
    let lastStepTime = 0;
    function animationLoop(timestamp) {
      if (isPlaying) {
        let speed = parseInt(document.getElementById('speedSelect').value, 10) || 5;
        if (timestamp - lastStepTime > 120) {
          tickSimulation(speed);
          lastStepTime = timestamp;
        }
      }

      drawCanvas();
      requestAnimationFrame(animationLoop);
    }

    // --- Event Listeners ---
    document.getElementById('btnPlay').addEventListener('click', () => {
      let allFinished = bots.every(b => b.finishTick !== null);
      if (allFinished) return;
      isPlaying = !isPlaying;
      updatePlayButton();
    });

    document.getElementById('btnStep').addEventListener('click', () => {
      isPlaying = false;
      updatePlayButton();
      tickSimulation(1);
    });

    document.getElementById('reset').addEventListener('click', () => {
      let seedVal = document.getElementById('seedInput').value;
      resetGame(seedVal !== "" ? seedVal : undefined);
    });

    document.getElementById('seedInput').addEventListener('change', (e) => {
      resetGame(e.target.value);
    });

    // Initialize Game
    resetGame(currentSeed);
    requestAnimationFrame(animationLoop);
  </script>
</body>
</html>
